// ignore_for_file: avoid_print
// Verification script: runs Dart implementations against golden data and
// reports maximum differences for each module.
//
// Usage: dart run tool/verify_parity.dart
//
// This is NOT a test — it's a diagnostic tool to verify that the Dart
// implementations actually produce the same values as the C++ Framework
// (golden data was generated by C++ Framework execution).

import 'dart:convert';
import 'dart:ffi';
import 'dart:io';
import 'dart:math' as math;
import 'dart:typed_data';

